import{z as d}from"zod";export const InsightPatternTypeSchema=d.enum(["recurring_character","unresolved_foreshadow","conflict_escalation","relationship_cluster","thematic_pattern"]),InsightSeveritySchema=d.enum(["info","warning","critical"]);const w=5,u=20,m=2,v=2,p=3,C=new Set(["motif","symbol"]);export class InsightForge{vault;constructor(i){this.vault=i}detectPatterns(){const i=this.vault.getActive(),t=[];return t.push(...this.detectRecurringCharacters(i)),t.push(...this.detectUnresolvedForeshadows(i)),t.push(...this.detectConflictEscalation(i)),t.push(...this.detectRelationshipClusters(i)),t.push(...this.detectThematicPatterns(i)),t}detectRecurringCharacters(i){const t=new Map;for(const s of i)for(const a of s.triggers){const r=a.toLowerCase();let c=t.get(r);c||(c=new Set,t.set(r,c)),c.add(s.id)}const o=[];for(const[s,a]of t)if(a.size>w){const r=[...a];o.push({type:"recurring_character",description:`Trigger "${s}" appears in ${r.length} facts, indicating a recurring character or motif that may warrant consolidation or arc tracking.`,factIds:r,severity:"info"})}return o}detectUnresolvedForeshadows(i){const t=i.reduce((s,a)=>Math.max(s,a.chapterOrigin),0),o=i.filter(s=>s.category==="foreshadow"&&s.status==="active"&&t-s.chapterOrigin>=u);return o.length===0?[]:[{type:"unresolved_foreshadow",description:`${o.length} foreshadow(s) have been active for ${u}+ chapters (current chapter: ${t}) without resolution. Consider resolving or explicitly archiving them.`,factIds:o.map(s=>s.id),severity:"warning"}]}detectConflictEscalation(i){const t=i.filter(r=>r.category==="conflict"&&r.status==="active").sort((r,c)=>r.chapterOrigin-c.chapterOrigin);if(t.length<m)return[];let o=!0;for(let r=1;r<t.length;r++)if(t[r].weight<t[r-1].weight){o=!1;break}if(!o)return[];const a=t[t.length-1].weight-t[0].weight>=30?"critical":"warning";return[{type:"conflict_escalation",description:`Conflict weight has escalated from ${t[0].weight} to ${t[t.length-1].weight} over ${t.length} conflict facts. The narrative tension is rising without relief \u2014 consider introducing a resolution or cooldown.`,factIds:t.map(r=>r.id),severity:a}]}detectRelationshipClusters(i){const t=i.filter(e=>e.category==="relation"&&e.status==="active");if(t.length<p)return[];const o=new Map,s=t.map((e,n)=>n),a=e=>{for(;s[e]!==e;)s[e]=s[s[e]],e=s[e];return e},r=(e,n)=>{const h=a(e),g=a(n);h!==g&&(s[h]=g)},c=(e,n)=>{const h=new Set(n.triggers.map(f=>f.toLowerCase()));let g=0;for(const f of e.triggers)h.has(f.toLowerCase())&&g++;return g};for(let e=0;e<t.length;e++)for(let n=e+1;n<t.length;n++)c(t[e],t[n])>=v&&r(e,n);for(let e=0;e<t.length;e++){const n=a(e);let h=o.get(n);h||(h=[],o.set(n,h)),h.push(t[e])}const l=[];for(const e of o.values())e.length>=p&&l.push({type:"relationship_cluster",description:`${e.length} relation facts share common characters, forming a relationship cluster. This may indicate a complex social web that could benefit from a dedicated relationship summary.`,factIds:e.map(n=>n.id),severity:"info"});return l}detectThematicPatterns(i){const t=i.filter(r=>C.has(r.category)&&r.status==="active"),o=i.filter(r=>r.domain==="plot_thread"&&r.status==="active");if(t.length===0||o.length===0)return[];const s=new Set;for(const r of o)for(const c of r.triggers)s.add(c.toLowerCase());const a=[];for(const r of t){const c=r.triggers.filter(l=>s.has(l.toLowerCase()));if(c.length>0){const l=o.filter(e=>e.triggers.some(n=>c.includes(n.toLowerCase())));a.push({type:"thematic_pattern",description:`Thematic fact "${r.label}" (${r.category}) shares triggers [${c.join(", ")}] with ${l.length} plot-thread fact(s), indicating this motif/symbol is actively woven into the plot.`,factIds:[r.id,...l.map(e=>e.id)],severity:"info"})}}return a}}
